parameters.jsCode:
const job = $('GetPendingJob').first().json;
return [{
  json: {
    id: job.id,
    name: job.title,
    type: 'task',
    status: 'in_progress',
    agent: job.agent,
    prompts: {
      user: job.instructions,
      core: 'core-prompt-v1',
      context: job.instructions
    },
    metadata: {
      inputType: 'task',
      telegram: {
        channelId: job.channel_id,
        messageId: null
      }
    }
  }
}];

let input = $input.first().json;

// Detect task JSON format vs legacy format
const isTaskJson = input.prompts !== undefined;

const inputType = isTaskJson ? (input.metadata?.inputType ?? 'unknown')       : (input.InputType ?? 'unknown');
const userInput = isTaskJson ? (input.prompts?.user ?? '')                    : (input.RequestInput?.input ?? '');
const channelID = isTaskJson ? (input.metadata?.telegram?.channelId ?? null) : (input.ChannelInformation?.ChannelID ?? null);
const messageID = isTaskJson ? (input.metadata?.telegram?.messageId ?? null) : (input.ChannelInformation?.MessageID ?? null);

return {
  InputType: inputType,
  RequestInput: {
    input: userInput + "\n\n###OUTPUT###\nStart your final answer with the exact token RESPONSE: on its own line."
  },
  ChannelInformation: {
    ChannelID: channelID,
    MessageID: messageID
  }
};

parameters.query:
SELECT channel_id, soul, user_profile, preferences, current_focus, onboarding_step
FROM user_profile
WHERE channel_id = {{ $('SetVars').first().json.ChannelInformation.ChannelID }}
LIMIT 1;

parameters.jsCode:
try {
  const allItems = $input.all();
  const profile = (allItems.length > 0 && allItems[0].json && allItems[0].json.channel_id != null)
    ? allItems[0].json
    : null;

  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;

  const hasProfile = profile !== null;
  const onboardingStep = hasProfile ? (profile.onboarding_step ?? 1) : 1;

  // â”€â”€ Current datetime injected on every execution â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const now = new Date();
  const timeContext = `DATE & TIME:
Current datetime: ${now.toISOString()}
Local datetime:   ${now.toLocaleString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
Timezone:         Europe/Amsterdam
Day of week:      ${now.toLocaleDateString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long' })}`;

  let systemPrompt = '';

  // â”€â”€ ONBOARDING MODE â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  if (!hasProfile || onboardingStep > 0) {
    const step = onboardingStep || 1;

    const steps = {
      1: `You are setting yourself up as the user's personal AI assistant.

Your ONLY task right now is to warmly greet the user and ask this one question:
"Before we dive in, I'd love to define my own identity. What should I call myself, and how would you describe my personality and purpose? For example: 'Baxter â€” sharp and direct â€” helps me stay on top of work and life.'"

When they respond, call the UpdateProfile tool with:
- soul: their answer, preserved exactly
- next_onboarding_step: 2
Leave all other fields as empty strings.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,

      2: `You are Baxter, a personal AI assistant currently in setup.

Your soul has been defined. Now ask:
"Great. Now tell me a bit about you â€” your work, interests, goals, whatever you'd like me to keep in mind long-term."

When they respond, call UpdateProfile with:
- user_profile: a structured summary of what they shared (name, role, interests, goals)
- next_onboarding_step: 3
Leave other fields as empty strings.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,

      3: `You are Baxter, a personal AI assistant currently in setup.

One last question:
"Almost done â€” how do you prefer I communicate? Concise and direct, or more detailed? Any language or format preferences?"

When they respond, call UpdateProfile with:
- preferences: their answer
- next_onboarding_step: 0
Leave other fields as empty strings. After saving, confirm setup is complete and you are ready to help.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
    };

    systemPrompt = `${timeContext}\n\n` + (steps[step] || steps[1]);

  // â”€â”€ OPERATION MODE â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  } else {
    const soul        = profile.soul          || 'Baxter â€” curious, helpful and critical â€” personal AI assistant';
    const userProfile = profile.user_profile  || '';
    const prefs       = profile.preferences   || 'Clear and direct';
    const focus       = profile.current_focus || '';

    systemPrompt  = `${timeContext}\n\n`;
    systemPrompt += `You are ${soul}.\n\n`;
    systemPrompt += `LANGUAGE: Always respond in English only, regardless of input language.\n\n`;
    systemPrompt += `FORMAT: Use markdown where it aids readability â€” headers and bullets for lists, news summaries and structured data; plain prose for conversational replies. When presenting news, use: **Title** â€” one sentence summary. Source, date. Be direct and concise. Maximum 3 sentences for simple factual answers.\n\n`;

    if (userProfile) systemPrompt += `ABOUT THE USER:\n${userProfile}\n\n`;
    if (prefs)       systemPrompt += `COMMUNICATION STYLE: ${prefs}\n\n`;
    if (focus)       systemPrompt += `CURRENT FOCUS: ${focus}\n\n`;


    // â”€â”€ Task context (populated for background subtasks) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    try {
      const taskCtx = $('FetchTaskContext').first().json;
      if (taskCtx && taskCtx.parent_goal) {
        systemPrompt += `TASK GOAL: This subtask is part of the larger goal "${taskCtx.parent_name}":\n${taskCtx.parent_goal}\n\n`;
      }
      if (taskCtx && taskCtx.completed_siblings && taskCtx.completed_siblings.length > 0) {
        const sibLines = taskCtx.completed_siblings
          .map(s => `- ${s.name}:\n  ${(s.result || '(no result)').substring(0, 800)}`)
          .join('\n');
        systemPrompt += `COMPLETED PRIOR SUBTASKS (build on these results â€” do not repeat them):\n${sibLines}\n\n`;
      }
    } catch(e) { /* no task context â€” standalone task */ }
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    systemPrompt += `PROFILE: Update the user profile proactively using UpdateProfile whenever the user shares new information, changes a preference, or shifts focus.\n\n`;

    systemPrompt += `TOOLS: Use tools when they add value â€” do not call tools unnecessarily on every message.
1. Use LongTermMemory when the user references past events, asks what you remember, or the topic benefits from historical context.
2. Use ExecQuery only when you need specific recent conversation details.
3. Use ProjectManager for tasks, projects, subtasks, priorities or due dates.
4. Use CalendarManager for events, meetings, appointments or scheduling.
5. Use NewsTool for current events, local news, tech or AI news, or anything recently changed.
6. Call ResearchAgent for deeper research or real-time data not covered by NewsTool.
7. Only call GetSchema if you need to discover table structure.

TASK DELEGATION: When a request will take significant time or multiple steps, use CreateTask to run it in the background. Assign the appropriate agent (research, baxter, project_manager). Start immediately â€” do not ask for approval. Tell Max the task has started and what to expect. Use GetTaskStatus when Max asks for an update.

VISUALS: When explaining a system, process, architecture or set of connected ideas, proactively generate a sketch without asking first. Use SketchAgent to produce a Mermaid diagram and send it as an image via Telegram. Supported: architecture diagrams, flowcharts, mind maps, sequence diagrams.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`;
  }

  return [{ json: { systemPrompt, onboardingStep, hasProfile } }];

} catch (error) {
  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;
  const now = new Date();

  const systemPrompt = `DATE & TIME: ${now.toISOString()} (Europe/Amsterdam)

You are Baxter, a personal AI assistant. You are curious, helpful and critical.

LANGUAGE: Always respond in English only.
FORMAT: use markdown where it aids readability (headers, bullets for lists and summaries), plain prose for conversational replies. When presenting news summaries, use this structure: a bold headline, one sentence summary, and source + date on the same line. Separate items with a blank line. Be direct and concise. 

TOOLS: Always check available tools before responding. Follow this order:
1. Call LongTermMemory on every message to retrieve relevant context.
2. Call ExecQuery for recent history. Filter WHERE channel_id = ${channelID} ORDER BY created_at DESC LIMIT 10.
3. Use ProjectManager for tasks, projects, subtasks, priorities or due dates.
4. Use CalendarManager for events, meetings, appointments or scheduling.
5. Use NewsTool for current events, local news or anything recently changed.
6. Call ResearchAgent for deeper research or real-time data not covered by NewsTool.

TASK DELEGATION: Use CreateTask for multi-step or time-consuming tasks. Start immediately. Tell Max what's running.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`;

  return [{ json: { systemPrompt, onboardingStep: 0, hasProfile: false, fallback: true } }];
}

